[The order-swap absorbs the left inclusion into the right one]
  \label{lem:gr_awayMulCommEquiv_comp_awayInclLeft}
  \lean{AlgebraicGeometry.Grassmannian.awayMulCommEquiv_comp_awayInclLeft}
  \uses{def:gr_away_mul_comm_equiv, def:gr_away_incl_left, def:gr_away_incl_right, lem:gr_awayInclLeft_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:gr_awayInclRight_comp_algebraMap, lem:mathlib_away_lift}
  For \(x, y \in A\), pre-composing the order-swap isomorphism
  \(\mathrm{swap}_{x,y} : A[1/(xy)] \cong A[1/(yx)]\)
  (\cref{def:gr_away_mul_comm_equiv}) with the left away-inclusion
  \(\iota^{\mathrm{L}}_{x,y} : A[1/x] \to A[1/(xy)]\)
  (\cref{def:gr_away_incl_left}) yields the right away-inclusion of the swapped
  pair:
  \[
    \mathrm{swap}_{x,y} \circ \iota^{\mathrm{L}}_{x,y}
      \;=\; \iota^{\mathrm{R}}_{y,x}
      \;:\; A[1/x] \longrightarrow A[1/(yx)] ,
  \]
  where \(\iota^{\mathrm{R}}_{y,x} : A[1/x] \to A[1/(yx)]\) is the right
  away-inclusion (\cref{def:gr_away_incl_right}) for the pair \((y, x)\). This is
  the order-swap coherence used to rotate the triple-overlap transitions.
\end{lemma}
\begin{proof}
  \uses{def:gr_away_mul_comm_equiv, def:gr_away_incl_left, def:gr_away_incl_right, lem:gr_awayInclLeft_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:gr_awayInclRight_comp_algebraMap, lem:mathlib_away_lift}
